$section_icon = static function (?string $name, string $class = ''): string {
    $class = 'h-3 w-3 shrink-0 opacity-70 ' . $class;
    $paths = match ($name) {
        'home' => '<path d="M3 10.5 12 3l9 7.5"/><path d="M5 9.5V21h14V9.5"/>',
        'server', 'proxmox' => '<rect x="3" y="4" width="18" height="6" rx="1.5"/><rect x="3" y="14" width="18" height="6" rx="1.5"/><path d="M7 7h.01M7 17h.01"/>',
        'guides' => '<path d="M4 5.5A2.5 2.5 0 0 1 6.5 3H11v16H6.5A2.5 2.5 0 0 0 4 21.5z"/><path d="M20 5.5A2.5 2.5 0 0 0 17.5 3H13v16h4.5a2.5 2.5 0 0 1 2.5 2.5z"/>',
        default => '<path d="M3 6.5A1.5 1.5 0 0 1 4.5 5H9l2 2h8.5A1.5 1.5 0 0 1 21 8.5v9a1.5 1.5 0 0 1-1.5 1.5h-15A1.5 1.5 0 0 1 3 17.5z"/>',
    };

    return '<svg class="' . trim($class) . '" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">' . $paths . '</svg>';
};
$render_tree = function (array $nodes, string $current, int $depth = 0) use (&$render_tree, $e): string {
    $html = '<ul class="m-0 list-none p-0' . ($depth > 0 ? ' relative mb-[9px] ms-3 mt-[3px] ps-3 before:absolute before:inset-y-1 before:[inset-inline-start:0] before:w-px before:bg-[var(--border)]' : '') . '" data-nav-list>';
    foreach ($nodes as $node) {
        $active = $node['url'] === $current;
        if ($node['type'] === 'folder') {
            $inside = $current === $node['url'] || str_starts_with($current, rtrim($node['url'], '/') . '/');
            $open = $inside || empty($node['collapsed']);
            $label = !empty($node['landing']) ? '<a class="min-w-0 flex-1 overflow-hidden text-ellipsis whitespace-nowrap' . ($active ? ' text-[var(--brand-strong)]' : '') . '" href="' . $e($node['url']) . '"' . ($active ? ' aria-current="page"' : '') . (!empty($node['private']) ? ' data-no-prefetch' : '') . '>' . $e($node['title']) . '</a>' : '<span class="min-w-0 overflow-hidden text-ellipsis">' . $e($node['title']) . '</span>';
            $html .= '<li class="my-px"><details class="group" data-nav-folder="' . $e($node['url']) . '" ' . ($open ? 'open' : '') . '><summary class="flex min-h-9 cursor-pointer list-none select-none items-center gap-2 rounded-[var(--radius-sm)] px-[9px] py-[7px] text-sm font-[620] leading-[1.4] text-[var(--text)] hover:bg-[var(--surface-subtle)] [&::-webkit-details-marker]:hidden [[data-density=compact]_&]:min-h-[27px] [[data-density=compact]_&]:py-1 [@media(pointer:coarse)]:min-h-10"><span class="h-1.5 w-1.5 shrink-0 -rotate-45 border-b-[1.5px] border-r-[1.5px] border-current text-[var(--faint)] transition-transform duration-150 group-open:rotate-45" aria-hidden="true"></span>' . $label . '</summary>';
            $html .= $render_tree($node['children'], $current, $depth + 1) . '</details></li>';
        } else {
            $badge = !empty($node['private']) ? '<span class="ms-auto inline-flex items-center rounded-full border border-[var(--border)] bg-[var(--surface-subtle)] px-[5px] py-[3px] text-[11px] font-[650] leading-none tracking-[.02em] text-[var(--muted)]">Private</span>' : (!empty($node['draft']) ? '<span class="ms-auto inline-flex items-center rounded-full border border-[var(--border)] bg-[var(--surface-subtle)] px-[5px] py-[3px] text-[11px] font-[650] leading-none tracking-[.02em] text-[var(--muted)]">Draft</span>' : '');
            $active_classes = $active ? ' relative bg-[var(--brand-soft)] font-[620] text-[var(--brand-strong)] before:absolute before:[inset-inline-start:0] before:h-[15px] before:w-0.5 before:rounded before:bg-[var(--brand)]' : '';
            $html .= '<li class="my-px"><a class="flex min-h-9 cursor-pointer select-none items-center gap-2 rounded-[var(--radius-sm)] px-[9px] py-[7px] text-sm leading-[1.4] text-[var(--muted)] hover:bg-[var(--surface-subtle)] hover:text-[var(--text)] [[data-density=compact]_&]:min-h-[27px] [[data-density=compact]_&]:py-1 [@media(pointer:coarse)]:min-h-10' . $active_classes . '" href="' . $e($node['url']) . '"' . ($active ? ' aria-current="page"' : '') . (!empty($node['private']) ? ' data-no-prefetch' : '') . '><span class="min-w-0 overflow-hidden text-ellipsis">' . $e($node['title']) . '</span>' . $badge . '</a></li>';
        }
    }
    return $html . '</ul>';
};
