      <?php if ($headings): ?><details class="group sticky top-2.5 z-40 mb-[22px] hidden rounded-[var(--radius-md)] border border-[var(--border)] bg-[color-mix(in_srgb,var(--surface)_92%,transparent)] shadow-[var(--shadow-sm)] backdrop-blur-[14px] max-[1200px]:block max-[840px]:top-[calc(var(--header)+10px)] print:hidden" data-toc-mobile><summary class="flex cursor-pointer list-none items-center gap-2 px-3 py-2.5 text-[13px] font-[620] text-[var(--muted)] group-open:border-b group-open:border-[var(--border)] [&::-webkit-details-marker]:hidden"><span>On this page</span><span class="min-w-0 flex-1 overflow-hidden text-ellipsis whitespace-nowrap text-right font-[480] text-[var(--faint)]" data-toc-current aria-hidden="true"></span><span class="h-1.5 w-1.5 rotate-45 border-b-[1.5px] border-r-[1.5px] border-current text-[var(--faint)] transition-transform duration-150 group-open:-rotate-[135deg]" aria-hidden="true"></span></summary><nav class="max-h-[min(46vh,340px)] overflow-auto overscroll-contain"><ul class="m-0 list-none p-2"><?php foreach ($headings as $heading): ?><li><a class="block rounded-[5px] px-2 py-1.5 text-[13px] text-[var(--muted)] hover:bg-[var(--surface-subtle)] hover:text-[var(--brand-strong)] data-[active=true]:bg-[var(--surface-subtle)] data-[active=true]:text-[var(--brand-strong)] [@media(pointer:coarse)]:min-h-10 <?= (int) $heading['level'] === 3 ? 'pl-[18px]' : '' ?>" href="#<?= $e($heading['id']) ?>"><?= $e($heading['title']) ?></a></li><?php endforeach; ?></ul></nav></details><?php endif; ?>
      <?= $content ?>
    </main>
  </div>
  <aside class="sticky top-0 h-screen h-dvh overflow-y-auto py-6 pe-1.5 ps-2 text-sm text-[var(--muted)] max-[1200px]:hidden print:hidden min-[841px]:[[data-reader-layout=notebook]_&]:hidden min-[841px]:[[data-reader-focus=true]_&]:hidden" data-toc aria-label="On this page">
    <?php if ($headings): ?><div class="relative ps-0.5 pt-[54px]" data-toc-inner><p class="mb-3 flex items-center gap-2 text-sm font-[640] text-[var(--text)]"><span class="text-[15px] leading-none text-[var(--faint)]" aria-hidden="true">≡</span>On this page</p><nav><ul class="relative m-0 list-none p-0 before:absolute before:inset-y-1.5 before:[inset-inline-start:0] before:w-px before:bg-[var(--border)]"><span class="pointer-events-none absolute [inset-inline-start:0] top-0 z-10 h-5 w-0.5 rounded-full bg-[var(--brand)] opacity-0 transition-[transform,height,opacity] duration-150" data-toc-indicator aria-hidden="true"></span><?php foreach ($headings as $heading): ?><li><a class="block py-[5px] <?= (int) $heading['level'] === 3 ? 'ps-6' : 'ps-[13px]' ?> leading-[1.45] hover:text-[var(--brand-strong)] data-[active=true]:font-semibold data-[active=true]:text-[var(--brand-strong)]" href="#<?= $e($heading['id']) ?>"><?= $e($heading['title']) ?></a></li><?php endforeach; ?></ul></nav><a class="mt-[17px] flex justify-between border-t border-[var(--border)] pt-[13px] text-[var(--faint)]" href="#main-content">Back to top <span>↑</span></a><?php if ($config['editor_enabled']): ?><a class="mt-2 flex justify-between py-2 text-[var(--faint)]" href="/admin">Open in Studio <span>↗</span></a><?php endif; ?></div><?php endif; ?>
  </aside>
</div>
<button class="fixed bottom-3.5 right-3.5 z-[80] grid h-[34px] w-[34px] [transform:translateY(8px)] place-items-center rounded-full border border-[var(--border-strong)] bg-[color-mix(in_srgb,var(--surface)_92%,transparent)] text-base leading-none text-[var(--text-strong)] opacity-0 shadow-[var(--shadow-sm)] backdrop-blur-lg transition-[opacity,transform,background] duration-150 hover:bg-[var(--surface-hover)] pointer-events-none min-[841px]:bottom-5 min-[841px]:right-5" type="button" data-back-to-top aria-label="Back to top" data-tooltip-placement="left"><span aria-hidden="true">↑</span></button>
<button class="fixed right-[35px] top-[30px] z-[85] hidden min-h-8 items-center gap-2 rounded-[var(--radius-sm)] border border-[var(--border-strong)] bg-[color-mix(in_srgb,var(--surface-raised)_94%,transparent)] px-[9px] py-1.5 text-[11px] font-[650] text-[var(--text-strong)] shadow-[var(--shadow-sm)] backdrop-blur-lg hover:bg-[var(--surface-hover)]" type="button" data-exit-reader-focus>Exit focus mode <kbd class="text-[10px] font-semibold text-[var(--faint)]">Esc</kbd></button>
<dialog class="mx-auto mt-[9vh] max-h-[76vh] w-[min(680px,calc(100vw_-_28px))] overflow-hidden rounded-[calc(var(--radius)+4px)] border border-[var(--border-strong)] bg-[var(--surface-raised)] p-0 text-[var(--text)] shadow-[var(--shadow-lg)] backdrop:bg-black/55 backdrop:backdrop-blur" data-search-dialog aria-label="Search documentation">
  <div>
    <div class="grid h-[57px] grid-cols-[18px_1fr_auto] items-center gap-2.5 border-b border-[var(--border)] px-3.5"><span class="relative inline-block h-3.5 w-3.5 rounded-full border-[1.6px] border-current text-[var(--faint)] after:absolute after:-bottom-0.5 after:-right-1 after:h-[1.6px] after:w-[5px] after:rotate-45 after:rounded after:bg-current" aria-hidden="true"></span><input class="w-full border-0 bg-transparent text-[15px] text-[var(--text-strong)] outline-none placeholder:text-[var(--faint)]" type="search" placeholder="Search pages and headings..." autocomplete="off" data-search-input><button class="cursor-pointer border-0 bg-transparent p-0" type="button" data-close-search aria-label="Close search"><kbd class="text-[10px] font-semibold text-[var(--faint)]">Esc</kbd></button></div>
    <div class="flex flex-wrap gap-1.5 px-3 pb-[3px] pt-2.5" data-search-filters hidden></div>
    <div class="max-h-[56vh] overflow-auto p-1.5" data-search-results><div class="flex min-h-[190px] flex-col items-center justify-center p-[30px] text-center text-[var(--muted)]"><span class="relative mb-3.5 h-9 w-9 rounded-[var(--radius-lg)] border border-[var(--border)] bg-[var(--surface-subtle)] before:absolute before:[inset-inline-start:10px] before:top-[9px] before:h-[11px] before:w-[11px] before:rounded-full before:border-[1.5px] before:border-[var(--faint)] after:absolute after:[inset-inline-start:20px] after:top-[21px] after:h-[1.5px] after:w-1.5 after:rotate-45 after:bg-[var(--faint)]" aria-hidden="true"></span><strong class="text-[var(--text-strong)]">Search the documentation</strong><p class="mt-1 text-[13px]">Find pages, commands, and individual sections.</p></div></div>
    <p class="sr-only" data-search-status aria-live="polite" aria-atomic="true"></p>
    <div class="flex h-[39px] items-center justify-end gap-3.5 border-t border-[var(--border)] bg-[var(--surface-subtle)] px-3 text-xs text-[var(--faint)] max-[540px]:justify-center [&>span]:flex [&>span]:items-center [&>span]:gap-[3px] [&>span:nth-child(2)]:max-[540px]:hidden [&_kbd]:min-h-4 [&_kbd]:px-1 [&_kbd]:py-px [&_kbd]:text-[11px]"><span><kbd>↑</kbd><kbd>↓</kbd> Navigate</span><span><kbd>Enter</kbd> Open</span><span><kbd>Esc</kbd> Close</span></div>
  </div>
</dialog>
<dialog class="m-auto max-h-[calc(100dvh_-_28px)] w-[min(420px,calc(100vw_-_28px))] overflow-hidden rounded-[calc(var(--radius)+2px)] border border-[var(--border)] bg-[var(--surface)] p-0 text-[var(--text)] shadow-[var(--shadow-lg)] backdrop:bg-black/40" data-reader-preferences-dialog aria-labelledby="reading-preferences-title">
  <form class="grid gap-4" method="dialog">
    <header class="flex items-center justify-between gap-3 border-b border-[var(--border)] px-[15px] py-[13px]"><div><p class="mb-0.5 text-[9px] font-semibold uppercase tracking-[.06em] text-[var(--brand-strong)]">Reader</p><strong class="text-[13px]" id="reading-preferences-title">Reading preferences</strong></div><button class="grid h-7 w-7 place-items-center rounded-md border border-[var(--border)] bg-[var(--surface-subtle)] text-[19px] leading-none text-[var(--text-strong)]" type="submit" aria-label="Close reading preferences">&times;</button></header>
    <fieldset class="grid gap-1.5 border-0 px-[15px]"><legend class="p-0 text-[11px] font-bold text-[var(--muted)]">Text size</legend><div class="grid grid-cols-3 gap-1.5"><label class="grid min-h-8 cursor-pointer place-items-center rounded-md border border-[var(--border)] bg-[var(--surface-subtle)] text-[11px] text-[var(--muted)] has-checked:border-[color-mix(in_srgb,var(--brand)_60%,var(--border))] has-checked:bg-[var(--brand-soft)] has-checked:font-semibold has-checked:text-[var(--brand-strong)]"><input class="pointer-events-none absolute opacity-0" type="radio" name="reading-text-size" value="small">Compact</label><label class="grid min-h-8 cursor-pointer place-items-center rounded-md border border-[var(--border)] bg-[var(--surface-subtle)] text-[11px] text-[var(--muted)] has-checked:border-[color-mix(in_srgb,var(--brand)_60%,var(--border))] has-checked:bg-[var(--brand-soft)] has-checked:font-semibold has-checked:text-[var(--brand-strong)]"><input class="pointer-events-none absolute opacity-0" type="radio" name="reading-text-size" value="default">Default</label><label class="grid min-h-8 cursor-pointer place-items-center rounded-md border border-[var(--border)] bg-[var(--surface-subtle)] text-[11px] text-[var(--muted)] has-checked:border-[color-mix(in_srgb,var(--brand)_60%,var(--border))] has-checked:bg-[var(--brand-soft)] has-checked:font-semibold has-checked:text-[var(--brand-strong)]"><input class="pointer-events-none absolute opacity-0" type="radio" name="reading-text-size" value="large">Large</label></div></fieldset>
    <fieldset class="grid gap-1.5 border-0 px-[15px]"><legend class="p-0 text-[11px] font-bold text-[var(--muted)]">Content width</legend><div class="grid grid-cols-3 gap-1.5"><label class="grid min-h-8 cursor-pointer place-items-center rounded-md border border-[var(--border)] bg-[var(--surface-subtle)] text-[11px] text-[var(--muted)] has-checked:border-[color-mix(in_srgb,var(--brand)_60%,var(--border))] has-checked:bg-[var(--brand-soft)] has-checked:font-semibold has-checked:text-[var(--brand-strong)]"><input class="pointer-events-none absolute opacity-0" type="radio" name="reading-content-width" value="compact">Compact</label><label class="grid min-h-8 cursor-pointer place-items-center rounded-md border border-[var(--border)] bg-[var(--surface-subtle)] text-[11px] text-[var(--muted)] has-checked:border-[color-mix(in_srgb,var(--brand)_60%,var(--border))] has-checked:bg-[var(--brand-soft)] has-checked:font-semibold has-checked:text-[var(--brand-strong)]"><input class="pointer-events-none absolute opacity-0" type="radio" name="reading-content-width" value="default">Default</label><label class="grid min-h-8 cursor-pointer place-items-center rounded-md border border-[var(--border)] bg-[var(--surface-subtle)] text-[11px] text-[var(--muted)] has-checked:border-[color-mix(in_srgb,var(--brand)_60%,var(--border))] has-checked:bg-[var(--brand-soft)] has-checked:font-semibold has-checked:text-[var(--brand-strong)]"><input class="pointer-events-none absolute opacity-0" type="radio" name="reading-content-width" value="wide">Wide</label></div></fieldset>
    <fieldset class="grid gap-1.5 border-0 px-[15px]"><legend class="p-0 text-[11px] font-bold text-[var(--muted)]">Layout</legend><div class="grid grid-cols-3 gap-1.5"><label class="grid min-h-8 cursor-pointer place-items-center rounded-md border border-[var(--border)] bg-[var(--surface-subtle)] text-[11px] text-[var(--muted)] has-checked:border-[color-mix(in_srgb,var(--brand)_60%,var(--border))] has-checked:bg-[var(--brand-soft)] has-checked:font-semibold has-checked:text-[var(--brand-strong)]"><input class="pointer-events-none absolute opacity-0" type="radio" name="reading-layout" value="standard">Standard</label><label class="grid min-h-8 cursor-pointer place-items-center rounded-md border border-[var(--border)] bg-[var(--surface-subtle)] text-[11px] text-[var(--muted)] has-checked:border-[color-mix(in_srgb,var(--brand)_60%,var(--border))] has-checked:bg-[var(--brand-soft)] has-checked:font-semibold has-checked:text-[var(--brand-strong)]"><input class="pointer-events-none absolute opacity-0" type="radio" name="reading-layout" value="notebook">Notebook</label><label class="grid min-h-8 cursor-pointer place-items-center rounded-md border border-[var(--border)] bg-[var(--surface-subtle)] text-[11px] text-[var(--muted)] has-checked:border-[color-mix(in_srgb,var(--brand)_60%,var(--border))] has-checked:bg-[var(--brand-soft)] has-checked:font-semibold has-checked:text-[var(--brand-strong)]"><input class="pointer-events-none absolute opacity-0" type="radio" name="reading-layout" value="focus">Focus</label></div><small class="text-[10.5px] text-[var(--muted)]">Notebook keeps compact navigation; Focus hides surrounding navigation.</small></fieldset>
    <footer class="flex items-center justify-between gap-3 border-t border-[var(--border)] px-[15px] py-[13px]"><button class="bg-transparent py-1.5 text-[11px] text-[var(--muted)]" type="button" data-reset-reading-preferences>Reset preferences</button><button class="rounded-[var(--radius-sm)] bg-[var(--brand)] px-3.5 py-2 text-sm font-semibold text-white hover:opacity-90" type="submit">Done</button></footer>
  </form>
</dialog>
